if (cuentas.length==0){
   swal("Seleccióne al menos una cuenta");
   return;
}

swal("Continuar la actualizacion de datos ?", {
    buttons: {
     cancel: "No",
    proceed: {
       text: "Si",
      value: "proceed",
    }
  },
})
.then((value) => {
   switch (value) {
      case "proceed":
         var popup = Runner.displayPopup( {
            url: "actualizar_banco.php?cuentas="+cuentas,
          width: "50%",
         height: "50%",
         header: 'Actualizando datos',
    beforeClose: function(popup) {
      location.reload(true)
      return true; 
    }
});
     break;

   default:
      swal("Proceso cancelado!");
     break;
   }
});
